import{_ as n,o as a,c as t,a2 as e}from"./chunks/framework.B72_uj9U.js";const d=JSON.parse('{"title":"Single vs Multi Turn","description":"Compare single-turn request-response patterns with multi-turn agentic conversations and their trade-offs.","frontmatter":{"title":"Single vs Multi Turn","description":"Compare single-turn request-response patterns with multi-turn agentic conversations and their trade-offs."},"headers":[],"relativePath":"learn/project/03-the-agentic-loop/10-single-vs-multi-turn.md","filePath":"learn/project/03-the-agentic-loop/10-single-vs-multi-turn.md"}'),o={name:"learn/project/03-the-agentic-loop/10-single-vs-multi-turn.md"};function l(p,s,r,c,i,y){return a(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="single-vs-multi-turn" tabindex="-1">Single vs Multi Turn <a class="header-anchor" href="#single-vs-multi-turn" aria-label="Permalink to &quot;Single vs Multi Turn&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>When a single LLM call is sufficient versus when the agentic loop must iterate multiple times</li><li>How multi-turn interactions accumulate context and why that affects both quality and cost</li><li>How to design your agent so users can switch between single-shot mode and full agentic mode</li></ul></blockquote><p>Not every user request needs the full agentic loop. Some questions have straightforward answers that the model can provide in a single call. Others require reading files, making changes, and verifying results across many turns. Understanding this spectrum helps you design an agent that is efficient for simple queries and powerful for complex tasks.</p><h2 id="the-single-turn-case" tabindex="-1">The Single-Turn Case <a class="header-anchor" href="#the-single-turn-case" aria-label="Permalink to &quot;The Single-Turn Case&quot;">​</a></h2><p>A single-turn interaction is one where the model responds with <code>stop_reason: &quot;end_turn&quot;</code> on the first call. No tools, no loop iteration -- just a question and an answer.</p><p>Examples of single-turn interactions:</p><ul><li>&quot;What does the <code>?</code> operator do in Rust?&quot;</li><li>&quot;Write me a function that reverses a string.&quot;</li><li>&quot;Explain the difference between <code>&amp;str</code> and <code>String</code>.&quot;</li></ul><p>In these cases, the agentic loop runs exactly once:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>User message → LLM call → end_turn → return response</span></span></code></pre></div><p>The loop overhead is minimal -- one API call, one match on <code>stop_reason</code>, one exit. Your loop handles this case naturally without any special code:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// The loop handles single-turn interactions automatically.</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// If the model doesn&#39;t need tools, it responds with end_turn</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// on the first iteration and the loop exits immediately.</span></span>
<span class="line"><span style="color:#CBA6F7;">loop</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> response </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;"> self</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">call_api</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">state</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CDD6F4;">    state</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">add_assistant_message</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">response</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">content</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">clone</span><span style="color:#9399B2;">());</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    match</span><span style="color:#CDD6F4;"> response</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">stop_reason</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">as_deref</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        Some</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;end_turn&quot;</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">            // Single turn: model answered directly</span></span>
<span class="line"><span style="color:#CBA6F7;">            return</span><span style="color:#F9E2AF;font-style:italic;"> Ok</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">LoopResult</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">Complete</span><span style="color:#9399B2;">(</span><span style="color:#89B4FA;font-style:italic;">extract_text</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">response</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">)));</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        Some</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;tool_use&quot;</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">            // Multi-turn: tools needed</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">            // ...</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        // ...</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><h2 id="the-multi-turn-case" tabindex="-1">The Multi-Turn Case <a class="header-anchor" href="#the-multi-turn-case" aria-label="Permalink to &quot;The Multi-Turn Case&quot;">​</a></h2><p>Multi-turn interactions are where the agentic loop earns its keep. The model needs to interact with the world -- reading files, running commands, checking results -- before it can answer.</p><p>Consider &quot;Add proper error handling to src/main.rs.&quot; This triggers a multi-turn sequence:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Turn 1: User asks → Model calls read_file(&quot;src/main.rs&quot;)</span></span>
<span class="line"><span>Turn 2: Model sees file contents → Calls write_file(&quot;src/main.rs&quot;, new_content)</span></span>
<span class="line"><span>Turn 3: Model sees write confirmation → Calls run_command(&quot;cargo check&quot;)</span></span>
<span class="line"><span>Turn 4: Model sees compilation output → Responds with summary (end_turn)</span></span></code></pre></div><p>Four turns, three tool calls. Each turn adds at least two messages to the conversation state (the assistant&#39;s response and the tool result), so the message history grows from 1 message to 9 messages.</p><h2 id="the-cost-curve" tabindex="-1">The Cost Curve <a class="header-anchor" href="#the-cost-curve" aria-label="Permalink to &quot;The Cost Curve&quot;">​</a></h2><p>Multi-turn interactions are more expensive in two ways: API cost and latency. Here is how the costs scale:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Turn 1: Input tokens = system_prompt + user_message</span></span>
<span class="line"><span>Turn 2: Input tokens = system_prompt + user_message + assistant_1 + tool_result_1</span></span>
<span class="line"><span>Turn 3: Input tokens = system_prompt + all_previous_messages</span></span>
<span class="line"><span>Turn N: Input tokens = system_prompt + ALL previous messages</span></span></code></pre></div><p>Because the full history is sent with every call, input tokens grow <em>quadratically</em> with the number of turns. A 4-turn interaction does not cost 4x a single turn -- it costs roughly 1x + 2x + 3x + 4x = 10x in input tokens (the exact numbers depend on message sizes, but the growth pattern is real).</p><p>Let&#39;s quantify this with a concrete example:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">/// Estimate the cumulative input token cost of a multi-turn interaction.</span></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> estimate_cumulative_cost</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#EBA0AC;">    system_tokens</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> usize</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;">    message_tokens</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#9399B2;">[</span><span style="color:#CBA6F7;">usize</span><span style="color:#9399B2;">],</span><span style="color:#6C7086;font-style:italic;">  // tokens per message</span></span>
<span class="line"><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#CBA6F7;"> usize</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CBA6F7;"> mut</span><span style="color:#CDD6F4;"> total </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 0</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    for</span><span style="color:#CDD6F4;"> turn </span><span style="color:#CBA6F7;">in</span><span style="color:#FAB387;"> 0</span><span style="color:#94E2D5;">..</span><span style="color:#CDD6F4;">message_tokens</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">len</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        // Each API call sends the system prompt plus all messages so far</span></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> input_for_this_call </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> system_tokens</span></span>
<span class="line"><span style="color:#94E2D5;">            +</span><span style="color:#CDD6F4;"> message_tokens</span><span style="color:#9399B2;">[</span><span style="color:#94E2D5;">..=</span><span style="color:#CDD6F4;">turn</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">iter</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">sum</span><span style="color:#94E2D5;">::</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">usize</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#CDD6F4;">        total </span><span style="color:#94E2D5;">+=</span><span style="color:#CDD6F4;"> input_for_this_call</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#CDD6F4;">    total</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">cfg</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">test</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#CBA6F7;">mod</span><span style="color:#FAB387;"> tests</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    use</span><span style="color:#CBA6F7;"> super</span><span style="color:#94E2D5;">::*</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">test</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CBA6F7;">    fn</span><span style="color:#89B4FA;font-style:italic;"> test_cost_growth</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> system </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 500</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;"> // 500-token system prompt</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        // 8 messages: user, asst+tool, result, asst+tool, result, asst+tool, result, asst_final</span></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> messages </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> vec!</span><span style="color:#9399B2;">[</span><span style="color:#FAB387;">100</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 200</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 500</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 150</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 30</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 200</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 800</span><span style="color:#9399B2;">,</span><span style="color:#FAB387;"> 100</span><span style="color:#9399B2;">];</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> total </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> estimate_cumulative_cost</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">system</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        // Much more than 8x a single message due to cumulative history</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">        println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Total input tokens across all calls: </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> total</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">        assert!</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">total </span><span style="color:#94E2D5;">&gt;</span><span style="color:#CDD6F4;"> messages</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">iter</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">sum</span><span style="color:#94E2D5;">::</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">usize</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> *</span><span style="color:#FAB387;"> 2</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>If you have built chatbots in Python, you have probably noticed that API costs are manageable for single-turn use. The moment you add tool use and the conversation grows, costs jump significantly. This is the same in Rust -- the language does not affect the API cost. What Rust <em>can</em> help with is efficient token counting and context management, because you can track the exact size of your serialized messages without relying on estimated character counts.</p></div><h2 id="when-single-turn-is-enough" tabindex="-1">When Single-Turn Is Enough <a class="header-anchor" href="#when-single-turn-is-enough" aria-label="Permalink to &quot;When Single-Turn Is Enough&quot;">​</a></h2><p>Not every agent request needs tools. Design your agent to handle simple questions efficiently. Here are guidelines for when single-turn is appropriate:</p><p><strong>Knowledge questions</strong>: &quot;What does this Rust syntax mean?&quot; The model has this knowledge and does not need to read any files.</p><p><strong>Code generation from a description</strong>: &quot;Write a function that parses a CSV file.&quot; The model can generate this from its training data.</p><p><strong>Explanations of provided code</strong>: If the user pastes code directly into their message, the model can analyze it without tool calls.</p><p>The key insight: if the model <em>already has all the information it needs</em> in the conversation history, it does not need tools and will respond in a single turn.</p><h2 id="when-multi-turn-is-required" tabindex="-1">When Multi-Turn Is Required <a class="header-anchor" href="#when-multi-turn-is-required" aria-label="Permalink to &quot;When Multi-Turn Is Required&quot;">​</a></h2><p>Tool calls are needed when the model must interact with the user&#39;s specific environment:</p><p><strong>Reading the codebase</strong>: &quot;Explain what the <code>Agent</code> struct does.&quot; The model needs to read <code>src/agent.rs</code> to answer this accurately.</p><p><strong>Making changes</strong>: &quot;Fix the compilation error.&quot; The model needs to read the error, read the relevant file, make a change, and verify it compiles.</p><p><strong>Gathering information</strong>: &quot;What dependencies does this project use?&quot; The model needs to read <code>Cargo.toml</code>.</p><p><strong>Verification</strong>: &quot;Refactor this function and make sure the tests still pass.&quot; The model needs to make changes and then run the test suite.</p><h2 id="designing-for-both-modes" tabindex="-1">Designing for Both Modes <a class="header-anchor" href="#designing-for-both-modes" aria-label="Permalink to &quot;Designing for Both Modes&quot;">​</a></h2><p>Your agent should handle both cases without the user needing to switch modes. The agentic loop already does this naturally -- if no tool calls are needed, it exits on the first iteration. But there are some design considerations:</p><p><strong>System prompt guidance</strong>: Your system prompt can influence whether the model uses tools. A prompt that says &quot;Always read the file before making changes&quot; will cause more tool calls than one that says &quot;Answer directly when possible, use tools only when needed.&quot;</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Encourage efficient tool use in the system prompt</span></span>
<span class="line"><span style="color:#CBA6F7;">let</span><span style="color:#CDD6F4;"> system_prompt </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;\\</span></span>
<span class="line"><span style="color:#A6E3A1;">You are a coding assistant with access to file and shell tools. \\</span></span>
<span class="line"><span style="color:#A6E3A1;">Answer questions directly from your knowledge when possible. \\</span></span>
<span class="line"><span style="color:#A6E3A1;">Use tools only when you need to interact with the user&#39;s actual codebase — \\</span></span>
<span class="line"><span style="color:#A6E3A1;">reading files, writing changes, running commands, or checking results.&quot;</span><span style="color:#9399B2;">;</span></span></code></pre></div><p><strong>Display feedback</strong>: In multi-turn mode, the user is waiting while the agent works. Good agents show progress during tool execution:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> display_progress</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;">call</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">ToolCall</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    match</span><span style="color:#CDD6F4;"> call</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">name</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">as_str</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;read_file&quot;</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">            let</span><span style="color:#CDD6F4;"> path </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> call</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">input</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;path&quot;</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">as_str</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">unwrap_or</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;unknown&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">            println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;  Reading </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">...&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> path</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;write_file&quot;</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">            let</span><span style="color:#CDD6F4;"> path </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> call</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">input</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;path&quot;</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">as_str</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">unwrap_or</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;unknown&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">            println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;  Writing </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">...&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> path</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;run_command&quot;</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">            let</span><span style="color:#CDD6F4;"> cmd </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> call</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">input</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;command&quot;</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">as_str</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">unwrap_or</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;unknown&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">            println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;  Running \`</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">\`...&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> cmd</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#CDD6F4;">        other </span><span style="color:#94E2D5;">=&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">            println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;  Running tool &#39;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&#39;...&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> other</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Cost transparency</strong>: Consider showing the user how many turns and tokens a request consumed:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">impl</span><span style="color:#F9E2AF;font-style:italic;"> LoopResult</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> summary</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> turns</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> usize</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> usage</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">Usage</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> status </span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;"> match</span><span style="color:#F38BA8;"> self</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            LoopResult</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">Complete</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">_</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#A6E3A1;"> &quot;Completed&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            LoopResult</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">MaxTokens</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">_</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#A6E3A1;"> &quot;Truncated (max tokens)&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            LoopResult</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">TurnLimitReached</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">_</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#A6E3A1;"> &quot;Stopped (turn limit)&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            LoopResult</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">ContextOverflow</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#A6E3A1;"> &quot;Stopped (context overflow)&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">        };</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">        format!</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#A6E3A1;">            &quot;[</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> in </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> turn(s), </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> input + </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> output tokens]&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">            status</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> turns</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> usage</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">input_tokens</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> usage</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">output_tokens</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">        )</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Claude Code visually distinguishes between single-turn and multi-turn interactions. For simple questions, it shows the response immediately. For tool-using interactions, it displays each tool call as it happens with a progress indicator -- &quot;Reading src/main.rs... Writing src/main.rs... Running cargo check...&quot; This gives the user confidence that the agent is making progress and lets them interrupt if it goes off track. OpenCode takes a similar approach, showing tool calls inline as they execute.</p></div><h2 id="the-spectrum-in-practice" tabindex="-1">The Spectrum in Practice <a class="header-anchor" href="#the-spectrum-in-practice" aria-label="Permalink to &quot;The Spectrum in Practice&quot;">​</a></h2><p>Real-world agent usage spans the full spectrum:</p><table tabindex="0"><thead><tr><th>Request type</th><th>Turns</th><th>Tool calls</th><th>Token cost</th></tr></thead><tbody><tr><td>&quot;What is a lifetime in Rust?&quot;</td><td>1</td><td>0</td><td>Low</td></tr><tr><td>&quot;Read src/main.rs&quot;</td><td>2</td><td>1</td><td>Low-medium</td></tr><tr><td>&quot;Add logging to the agent module&quot;</td><td>3-5</td><td>2-4</td><td>Medium</td></tr><tr><td>&quot;Refactor the error handling across all files&quot;</td><td>8-15</td><td>6-12</td><td>High</td></tr><tr><td>&quot;Set up a new feature with tests and docs&quot;</td><td>15-25</td><td>10-20</td><td>Very high</td></tr></tbody></table><p>Your turn limit (default 25) should accommodate the &quot;very high&quot; category while preventing truly runaway loops. If a user regularly hits the limit, they can increase it. If they mostly do simple queries, the loop exits on the first turn and the limit is irrelevant.</p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Single-turn interactions (no tools needed) are handled naturally by the agentic loop -- the model returns <code>end_turn</code> on the first iteration and the loop exits immediately</li><li>Multi-turn interactions grow cost quadratically because the full message history is sent with every API call -- a 4-turn interaction costs roughly 10x a single turn in input tokens</li><li>Design the system prompt to encourage efficient tool use: answer from knowledge when possible, use tools only when interacting with the actual codebase</li><li>Show progress during multi-turn interactions so the user knows the agent is working and can interrupt if needed</li><li>The same loop architecture handles both modes seamlessly; the model decides whether to use tools based on the request and context</li></ul>`,50)])])}const h=n(o,[["render",l]]);export{d as __pageData,h as default};
